import re
from collections import defaultdict

# Load books data
books_path = locals().get('var_functions.query_db:16')
with open(books_path, 'r') as f:
    books = json.load(f)

# Load reviews data
reviews_path = locals().get('var_functions.query_db:24')
with open(reviews_path, 'r') as f:
    reviews = json.load(f)

# Build book map with publication years using improved extraction
book_map = {}
year_patterns = [
    r'(January|February|March|April|May|June|July|August|September|October|November|December)\s+(\d{1,2}),?\s+(\d{4})',
    r'published[^\d]*(\d{4})',
    r'released[^\d]*(\d{4})',
    r'edition[^\d]*(\d{4})'
]

for book in books:
    book_id = book.get('book_id', '')
    match = re.search(r'bookid_(\d+)', book_id)
    if not match:
        continue

    book_num = int(match.group(1))
    try:
        rating_num = int(book.get('rating_number', 0))
    except:
        continue

    if rating_num <= 0:
        continue

    details = book.get('details', '')
    found_year = None

    # Try specific patterns first
    for pattern in year_patterns:
        m = re.search(pattern, details, re.IGNORECASE)
        if m:
            groups = [g for g in m.groups() if g and g.isdigit() and len(g) == 4]
            if groups:
                found_year = int(groups[0])
                break

    # Fallback: look for 4-digit numbers around date words
    if not found_year:
        date_words = ['January', 'February', 'March', 'April', 'May', 'June', 
                     'July', 'August', 'September', 'October', 'November', 'December',
                     'published', 'released', 'edition']
        lower_details = details.lower()

        for word in date_words:
            pos = lower_details.find(word.lower())
            if pos >= 0:
                after = details[pos+len(word):pos+len(word)+100]
                nums = re.findall(r'\b(19\d{2}|20\d{2}|21\d{2})\b', after)
                if nums and 1900 <= int(nums[0]) <= 2023:
                    found_year = int(nums[0])
                    break

    if found_year and 1900 <= found_year <= 2023:
        book_map[book_num] = {
            'decade': (found_year // 10) * 10,
            'year': found_year,
            'rating_number': rating_num
        }

# Process reviews
decade_books = defaultdict(set)
decade_stats = defaultdict(lambda: {'total_rating_sum': 0, 'total_review_count': 0})

for review in reviews:
    purchase_id = review.get('purchase_id', '')
    match = re.search(r'purchaseid_(\d+)', purchase_id)
    if not match:
        continue

    purchase_num = int(match.group(1))
    if purchase_num not in book_map:
        continue

    try:
        rating = float(review.get('rating', 0))
    except:
        continue

    decade = book_map[purchase_num]['decade']

    decade_books[decade].add(purchase_num)
    decade_stats[decade]['total_rating_sum'] += rating
    decade_stats[decade]['total_review_count'] += 1

# Calculate average ratings and filter by >= 10 distinct books
qualified_decades = {}
for decade, stats in decade_stats.items():
    num_books = len(decade_books[decade])
    if num_books >= 10:
        avg_rating = stats['total_rating_sum'] / stats['total_review_count']
        qualified_decades[decade] = {
            'average_rating': avg_rating,
            'distinct_books': num_books,
            'total_reviews': stats['total_review_count']
        }

# Find best decade
if qualified_decades:
    best_decade = max(qualified_decades.keys(), key=lambda d: qualified_decades[d]['average_rating'])
    best_data = qualified_decades[best_decade]

    print('__RESULT__:')
    print(json.dumps({
        'best_decade': f"{best_decade}s",
        'average_rating': round(best_data['average_rating'], 3),
        'distinct_books': best_data['distinct_books'],
        'total_reviews': best_data['total_reviews'],
        'books_mapped': len(book_map),
        'decades_qualified': len(qualified_decades)
    }))
else:
    # Debug info
    all_decades = {}
    for decade, stats in decade_stats.items():
        if stats['total_review_count'] > 0:
            avg = stats['total_rating_sum'] / stats['total_review_count']
            all_decades[f"{decade}s"] = {
                'avg_rating': round(avg, 3),
                'books': len(decade_books[decade]),
                'reviews': stats['total_review_count']
            }

    print('__RESULT__:')
    print(json.dumps({
        'message': 'No decade with 10+ distinct books',
        'books_with_years': len(book_map),
        'decades_with_data': all_decades
    }))"}
